public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input (can be from a form input, database, etc.)
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitize user input to prevent XSS attacks
        String sanitizedUserInput = sanitizeUserInput(userInput);

        // Properly handle user input with sanitized data
        String output = "Welcome, " + sanitizedUserInput;

        System.out.println(output);
    }

    private static String sanitizeUserInput(String userInput) {
        // Replace characters that can be used in XSS attacks with safe alternatives
        return userInput.replaceAll("<", "&lt;")
                        .replaceAll(">", "&gt;")
                        .replaceAll("&", "&amp;")
                        .replaceAll("\"", "&quot;")
                        .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
